export default function ReviewsSection() {
  const [visible, setVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section
      ref={ref}
      style={{
        background: '#0A2E6B',
        position: 'relative',
        overflow: 'hidden',
        padding: '96px 24px',
      }}
    >
      {/* Subtle grid texture */}
      <div style={{
        position: 'absolute', inset: 0, opacity: 0.04,
        backgroundImage: 'linear-gradient(rgba(255,255,255,0.5) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.5) 1px, transparent 1px)',
        backgroundSize: '40px 40px',
        pointerEvents: 'none',
      }} />

      {/* Teal glow */}
      <div style={{
        position: 'absolute', top: -120, right: -120,
        width: 400, height: 400,
        background: 'radial-gradient(circle, rgba(39,193,183,0.15) 0%, transparent 70%)',
        pointerEvents: 'none',
      }} />

      <div style={{ maxWidth: 1100, margin: '0 auto', position: 'relative' }}>

        {/* Header */}
        <div style={{
          textAlign: 'center', marginBottom: 56,
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateY(0)' : 'translateY(24px)',
          transition: 'opacity 0.6s ease, transform 0.6s ease',
        }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 10,
            background: 'rgba(255,255,255,0.07)',
            border: '1px solid rgba(255,255,255,0.12)',
            borderRadius: 40, padding: '8px 20px', marginBottom: 28,
          }}>
            <GoogleIcon />
            <span style={{ color: '#fff', fontSize: 14, fontWeight: 600 }}>5.0</span>
            <Stars />
            <span style={{ color: 'rgba(255,255,255,0.5)', fontSize: 13 }}>· 43 Google reviews</span>
          </div>

          <h2 style={{
            color: '#fff', fontSize: 'clamp(28px, 4vw, 42px)',
            fontWeight: 800, lineHeight: 1.15, margin: '0 0 14px',
          }}>
            Don't just take our word for it
          </h2>
          <p style={{ color: 'rgba(255,255,255,0.55)', fontSize: 17, maxWidth: 460, margin: '0 auto' }}>
            Real clients. Real results. See what people are saying.
          </p>
          <div style={{ width: 48, height: 3, background: '#27C1B7', borderRadius: 2, margin: '28px auto 0' }} />
        </div>

        {/* Cards */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(290px, 1fr))',
          gap: 20,
        }}>
          {reviews.map((r, i) => (
            <div
              key={r.name}
              style={{
                background: r.featured ? 'rgba(39,193,183,0.08)' : 'rgba(255,255,255,0.05)',
                border: r.featured ? '1px solid rgba(39,193,183,0.3)' : '1px solid rgba(255,255,255,0.09)',
                borderRadius: 20,
                padding: '26px 24px',
                display: 'flex',
                flexDirection: 'column',
                gap: 14,
                opacity: visible ? 1 : 0,
                transform: visible ? 'translateY(0)' : 'translateY(32px)',
                transition: `opacity 0.55s ease ${0.1 + i * 0.09}s, transform 0.55s ease ${0.1 + i * 0.09}s`,
              }}
            >
              {/* Reviewer */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <img
                  src={photos[r.photo]}
                  alt={r.name}
                  style={{
                    width: 48, height: 48,
                    borderRadius: '50%',
                    objectFit: 'cover',
                    border: r.featured ? '2px solid #27C1B7' : '2px solid rgba(255,255,255,0.15)',
                    flexShrink: 0,
                  }}
                />
                <div>
                  <div style={{ color: '#fff', fontSize: 14, fontWeight: 700, marginBottom: 3 }}>{r.name}</div>
                  <Stars />
                </div>
              </div>

              {/* Quote */}
              <div style={{ color: '#27C1B7', fontSize: 32, lineHeight: 1, opacity: 0.5, marginBottom: -6 }}>&#8220;</div>

              <p style={{
                color: 'rgba(255,255,255,0.75)',
                fontSize: 13.5,
                lineHeight: 1.72,
                flex: 1,
              }}>
                {r.text}
              </p>
            </div>
          ))}
        </div>

        {/* CTA */}
        <div style={{
          textAlign: 'center', marginTop: 48,
          opacity: visible ? 1 : 0,
          transition: 'opacity 0.6s ease 0.65s',
        }}>
          <a
            href="https://share.google/yRmM1i4FL0kiBMf5O"
            target="_blank"
            rel="noopener noreferrer"
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 8,
              color: '#27C1B7', fontSize: 15, fontWeight: 600,
              textDecoration: 'none',
              border: '1.5px solid rgba(39,193,183,0.35)',
              borderRadius: 40, padding: '12px 28px',
            }}
          >
            <GoogleIcon />
            Read all 43 reviews on Google
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#27C1B7" strokeWidth="2.5">
              <path d="M5 12h14M12 5l7 7-7 7"/>
            </svg>
          </a>
        </div>

      </div>
    </section>
  );
}
